def gen(rng, size):
    n = max(2, min(size, 300))
    parent = [0] * n
    for i in range(1, n):
        parent[i] = rng.randint(0, i - 1)
    edges = []
    for i in range(1, n):
        u, v = i, parent[i]
        if rng.random() < 0.5:
            edges.append([u, v])
        else:
            edges.append([v, u])
    rng.shuffle(edges)
    return [n, edges]

