from collections import deque

class Solution:
    def minEdgeReversals(self, n, edges):
        adj = [[] for _ in range(n)]
        for u, v in edges:
            adj[u].append((v, 0))
            adj[v].append((u, 1))
        ans = [0] * n
        for src in range(n):
            visited = [False] * n
            visited[src] = True
            total = 0
            dq = deque([src])
            while dq:
                u = dq.popleft()
                for v, w in adj[u]:
                    if not visited[v]:
                        visited[v] = True
                        total += w
                        dq.append(v)
            ans[src] = total
        return ans

