var minEdgeReversals = function(n, edges) {
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) {
        adj[u].push([v, 0]);
        adj[v].push([u, 1]);
    }
    const visited = new Array(n).fill(false);
    visited[0] = true;
    const parent = new Array(n).fill(-1);
    const weightToParent = new Array(n).fill(0);
    const order = [0];
    let total = 0;
    const queue = [0];
    let head = 0;
    while (head < queue.length) {
        const u = queue[head++];
        for (const [v, w] of adj[u]) {
            if (!visited[v]) {
                visited[v] = true;
                parent[v] = u;
                weightToParent[v] = w;
                total += w;
                order.push(v);
                queue.push(v);
            }
        }
    }
    const ans = new Array(n).fill(0);
    ans[0] = total;
    for (let i = 1; i < order.length; i++) {
        const v = order[i];
        const p = parent[v];
        const w = weightToParent[v];
        ans[v] = ans[p] + (1 - 2 * w);
    }
    return ans;
};
